def run_length_encode(data):
    if not data:
        return ""

    encoded_data = []
    count = 1
    current_char = data[0]

    for i in range(1, len(data)):
        if data[i] == current_char:
            count += 1
        else:
            encoded_data.append(str(count))
            encoded_data.append(current_char)
            current_char = data[i]
            count = 1

    encoded_data.append(str(count))
    encoded_data.append(current_char)

    return "".join(encoded_data)
